     1→"use client";
     2→
     3→import { useState } from "react";
     4→import { useRouter } from "next/navigation";
     5→import { Button } from "@/components/ui/button";
     6→import { Input } from "@/components/ui/input";
     7→import { Label } from "@/components/ui/label";
     8→import { Switch } from "@/components/ui/switch";
     9→import { Textarea } from "@/components/ui/textarea";
    10→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
    11→import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
    12→import type { Source, SourceInput } from "@/lib/api/types";
    13→
    14→interface SourceFormProps {
    15→  initial?: Source;
    16→  projectId?: string;
    17→  onSubmit: (input: SourceInput) => Promise<void>;
    18→  title: string;
    19→  redirectTo?: string;
    20→  onSuccess?: () => void;
    21→  onCancel?: () => void;
    22→}
    23→
    24→export function SourceForm({ initial, onSubmit, title, redirectTo, onSuccess, onCancel }: SourceFormProps) {
    25→  const router = useRouter();
    26→  const [saving, setSaving] = useState(false);
    27→  const [error, setError] = useState("");
    28→  const [provider, setProvider] = useState(initial?.provider ?? "dockerhub");
    29→  const [repository, setRepository] = useState(initial?.repository ?? "");
    30→  const [pollInterval, setPollInterval] = useState(String(initial?.poll_interval_seconds ?? 300));
    31→  const [enabled, setEnabled] = useState(initial?.enabled ?? true);
    32→  const [configJson, setConfigJson] = useState(
    33→    JSON.stringify(initial?.config ?? {}, null, 2)
    34→  );
    35→
    36→  const handleSubmit = async (e: React.FormEvent) => {
    37→    e.preventDefault();
    38→    setError("");
    39→
    40→    let parsedConfig: Record<string, unknown> | undefined;
    41→    if (configJson.trim() && configJson.trim() !== "{}") {
    42→      try {
    43→        parsedConfig = JSON.parse(configJson);
    44→      } catch {
    45→        setError("Config must be valid JSON");
    46→        return;
    47→      }
    48→    }
    49→
    50→    setSaving(true);
    51→    try {
    52→      await onSubmit({
    53→        provider,
    54→        repository,
    55→        poll_interval_seconds: Number(pollInterval),
    56→        enabled,
    57→        config: parsedConfig,
    58→      });
    59→      if (onSuccess) {
    60→        onSuccess();
    61→      } else {
    62→        router.push(redirectTo ?? "/sources");
    63→      }
    64→    } catch (err: unknown) {
    65→      setError(err instanceof Error ? err.message : "Failed to save");
    66→    } finally {
    67→      setSaving(false);
    68→    }
    69→  };
    70→
    71→  const handleCancel = () => {
    72→    if (onCancel) {
    73→      onCancel();
    74→    } else {
    75→      router.back();
    76→    }
    77→  };
    78→
    79→  const formContent = (
    80→    <form onSubmit={handleSubmit} className="space-y-4">
    81→      {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
    82→      <div className="space-y-2">
    83→        <Label>Provider</Label>
    84→        <Select value={provider} onValueChange={setProvider}>
    85→          <SelectTrigger><SelectValue /></SelectTrigger>
    86→          <SelectContent>
    87→            <SelectItem value="dockerhub">Docker Hub</SelectItem>
    88→            <SelectItem value="github">GitHub</SelectItem>
    89→          </SelectContent>
    90→        </Select>
    91→      </div>
    92→      <div className="space-y-2">
    93→        <Label htmlFor="repository">Repository</Label>
    94→        <Input id="repository" value={repository} onChange={(e) => setRepository(e.target.value)} placeholder="e.g. library/golang or ethereum/go-ethereum" required />
    95→      </div>
    96→      <div className="space-y-2">
    97→        <Label htmlFor="poll_interval">Poll Interval (seconds)</Label>
    98→        <Input id="poll_interval" type="number" min={60} value={pollInterval} onChange={(e) => setPollInterval(e.target.value)} />
    99→      </div>
   100→      <div className="space-y-2">
   101→        <Label htmlFor="config">Config (JSON, optional)</Label>
   102→        <Textarea
   103→          id="config"
   104→          value={configJson}
   105→          onChange={(e) => setConfigJson(e.target.value)}
   106→          rows={4}
   107→          className="font-mono text-sm"
   108→          placeholder="{}"
   109→        />
   110→      </div>
   111→      <div className="flex items-center gap-3">
   112→        <Switch checked={enabled} onCheckedChange={setEnabled} />
   113→        <Label>Enabled</Label>
   114→      </div>
   115→      <div className="flex justify-end gap-2">
   116→        <Button type="button" variant="outline" onClick={handleCancel}>Cancel</Button>
   117→        <Button type="submit" disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
   118→      </div>
   119→    </form>
   120→  );
   121→
   122→  if (onSuccess) {
   123→    return formContent;
   124→  }
   125→
   126→  return (
   127→    <Card className="mx-auto max-w-2xl">
   128→      <CardHeader><CardTitle>{title}</CardTitle></CardHeader>
   129→      <CardContent>
   130→        {formContent}
   131→      </CardContent>
   132→    </Card>
   133→  );
   134→}
   135→

