package ingestion

import (
	"context"
	"log/slog"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
)

// Orchestrator runs polling ingestion sources on a fixed interval.
type Orchestrator struct {
	service       *Service
	loader        *SourceLoader
	pool          *pgxpool.Pool
	staticSources []IIngestionSource // for testing only
	interval      time.Duration
}

// NewOrchestrator creates an orchestrator that dynamically loads enabled
// sources from the database on each poll cycle.
func NewOrchestrator(service *Service, loader *SourceLoader, pool *pgxpool.Pool, interval time.Duration) *Orchestrator {
	return &Orchestrator{service: service, loader: loader, pool: pool, interval: interval}
}

// NewOrchestratorWithSources creates an orchestrator with a static source list.
// Intended for testing; production code should use NewOrchestrator with a SourceLoader.
func NewOrchestratorWithSources(service *Service, sources []IIngestionSource, interval time.Duration) *Orchestrator {
	return &Orchestrator{service: service, staticSources: sources, interval: interval}
}

// Run polls all sources immediately, then on every tick. Blocks until ctx is cancelled.
func (o *Orchestrator) Run(ctx context.Context) {
	ticker := time.NewTicker(o.interval)
	defer ticker.Stop()

	o.pollAll(ctx)

	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			o.pollAll(ctx)
		}
	}
}

func (o *Orchestrator) pollAll(ctx context.Context) {
	sources := o.staticSources
	if sources == nil {
		var err error
		sources, err = o.loader.LoadEnabledSources(ctx)
		if err != nil {
			slog.Error("load sources failed", "err", err)
			return
		}
	}
	if len(sources) == 0 {
		slog.Debug("no enabled sources to poll")
		return
	}
	for _, src := range sources {
		results, err := src.FetchNewReleases(ctx)
		if err != nil {
			slog.Error("poll failed", "source", src.Name(), "err", err)
			o.updateSourcePollStatus(ctx, src.SourceID(), err)
			continue
		}
		o.updateSourcePollStatus(ctx, src.SourceID(), nil)
		if len(results) == 0 {
			continue
		}
		if err := o.service.ProcessResults(ctx, src.SourceID(), src.Name(), results); err != nil {
			slog.Error("process failed", "source", src.Name(), "err", err)
		}
	}
}

func (o *Orchestrator) updateSourcePollStatus(ctx context.Context, sourceID string, pollErr error) {
	if o.pool == nil {
		return
	}
	var lastError *string
	if pollErr != nil {
		s := pollErr.Error()
		lastError = &s
	}
	_, err := o.pool.Exec(ctx,
		`UPDATE sources SET last_polled_at = NOW(), last_error = $1 WHERE id = $2`,
		lastError, sourceID)
	if err != nil {
		slog.Error("update source poll status", "source", sourceID, "err", err)
	}
}

// web/lib/api/client.ts
import type {
  ApiResponse,
  Project,
  ProjectInput,
  Release,
  Source,
  SourceInput,
  Subscription,
  SubscriptionInput,
  NotificationChannel,
  ChannelInput,
  ContextSource,
  ContextSourceInput,
  SemanticRelease,
  AgentRun,
  HealthStatus,
  Stats,
  TrendData,
} from "./types";

const BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";

async function request<T>(path: string, init?: RequestInit): Promise<T> {
  const res = await fetch(`${BASE}${path}`, {
    headers: { "Content-Type": "application/json", ...init?.headers },
    ...init,
  });
  if (!res.ok) {
    const body = await res.json().catch(() => null);
    throw new Error(body?.error?.message ?? `Request failed: ${res.status}`);
  }
  if (res.status === 204) return null as T;
  return res.json();
}

// --- Projects ---

export const projects = {
  list: (page = 1, perPage = 25) =>
    request<ApiResponse<Project[]>>(`/projects?page=${page}&per_page=${perPage}`),
  get: (id: string) =>
    request<ApiResponse<Project>>(`/projects/${id}`),
  create: (input: ProjectInput) =>
    request<ApiResponse<Project>>("/projects", {
      method: "POST",
      body: JSON.stringify(input),
    }),
  update: (id: string, input: ProjectInput) =>
    request<ApiResponse<Project>>(`/projects/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/projects/${id}`, { method: "DELETE" }),
};

// --- Sources (nested under projects) ---

export const sources = {
  listByProject: (projectId: string, page = 1) =>
    request<ApiResponse<Source[]>>(`/projects/${projectId}/sources?page=${page}`),
  create: (projectId: string, input: SourceInput) =>
    request<ApiResponse<Source>>(`/projects/${projectId}/sources`, {
      method: "POST",
      body: JSON.stringify(input),
    }),
  get: (id: string) =>
    request<ApiResponse<Source>>(`/sources/${id}`),
  update: (id: string, input: SourceInput) =>
    request<ApiResponse<Source>>(`/sources/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/sources/${id}`, { method: "DELETE" }),
};

// --- Releases ---

export const releases = {
  list: (page = 1, perPage = 25) =>
    request<ApiResponse<Release[]>>(`/releases?page=${page}&per_page=${perPage}`),
  listBySource: (sourceId: string, page = 1) =>
    request<ApiResponse<Release[]>>(`/sources/${sourceId}/releases?page=${page}`),
  listByProject: (projectId: string, page = 1, perPage = 25) =>
