export function timeAgo(dateStr?: string | null): string {
  if (!dateStr) return "\u2014";
  const diff = Date.now() - new Date(dateStr).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs / 24)}d ago`;
}

export function normalizeRepository(provider: string, repo: string): string {
  let cleaned = repo.trim();
  if (provider === "github") {
    cleaned = cleaned
      .replace(/^https?:\/\/github\.com\//, "")
      .replace(/^github\.com\//, "")
      .replace(/\.git$/, "");
  } else if (provider === "dockerhub") {
    cleaned = cleaned
      .replace(/^https?:\/\/hub\.docker\.com\/r\//, "")
      .replace(/^hub\.docker\.com\/r\//, "")
      .replace(/^https?:\/\/hub\.docker\.com\/_\//, "")
      .replace(/^hub\.docker\.com\/_\//, "");
  }
  cleaned = cleaned.replace(/\/+$/, "");
  return cleaned;
}

